const staticData = $getWorkflowStaticData('global');

staticData.retry_count = (staticData.retry_count || 0) + 1;

return [{
  json: {
    retry_count: staticData.retry_count
  }
}];

const item = $input.first();
const telegramText = item.json.telegram_text || '';

const tickers = telegramText.match(/\$[A-Z]{2,6}/g) || [];

const seenTickers = new Set();
let result = telegramText;

tickers.forEach(ticker => {
  if (seenTickers.has(ticker)) {
    const regex = new RegExp('\\' + ticker + '(?!\\w)', 'g');
    let count = 0;
    result = result.replace(regex, (match) => {
      count++;
      return count === 1 ? match : match.substring(1);
    });
  }
  seenTickers.add(ticker);
});

return [{
  json: {
    ...item.json,
    telegram_text: result
  }
}]

