);

function countMatches(keywords1, keywords2) {
  const set2 = new Set(keywords2);
  return keywords1.filter(k => set2.has(k)).length;
}

let isDuplicate = false;
let matchedWith = '';

for (const theme of seenThemesData) {
  const seenKeywords = (theme.json.Topic_keywords || '').split(' ');
  const matches = countMatches(currentKeywords, seenKeywords);

  if (matches / currentKeywords.length > 0.5) {
    isDuplicate = true;
    matchedWith = theme.json.Topic_keywords;
    break;
  }
}

return [{
  json: {
    is_duplicate: isDuplicate,
    matched_with: matchedWith,
    current_keywords: currentKeywords.join(' '),
    twitter_text: $('Parse AI Output & Normalize Label').first().json.twitter_text,
